/* Voice search styles */
.voice-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.75);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  animation: fadeIn 0.3s ease forwards;
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

.voice-card {
  background: var(--surface-1);
  border: 1px solid var(--hairline);
  padding: 40px;
  border-radius: var(--radius-xl);
  box-shadow: var(--shadow-premium);
  text-align: center;
  display: flex;
  flex-direction: column;
  align-items: center;
  width: 340px;
  position: relative;
}

.voice-pulsar-container {
  position: relative;
  width: 100px;
  height: 100px;
  margin-bottom: 24px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.voice-ripple {
  position: absolute;
  width: 80px;
  height: 80px;
  border-radius: 50%;
  background: rgba(106, 76, 245, 0.25);
  animation: ripple 2s infinite ease-out;
}

.r1 { animation-delay: 0s; }
.r2 { animation-delay: 0.6s; }
.r3 { animation-delay: 1.2s; }

@keyframes ripple {
  from {
    transform: scale(0.8);
    opacity: 1;
  }
  to {
    transform: scale(2.2);
    opacity: 0;
  }
}

.voice-mic-icon {
  position: relative;
  width: 60px;
  height: 60px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--grad-violet) 0%, var(--grad-magenta) 100%);
  color: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 24px;
  box-shadow: 0 0 20px rgba(106, 76, 245, 0.4);
  z-index: 2;
}

.voice-status {
  font-family: 'Outfit', sans-serif;
  font-size: 18px;
  font-weight: 600;
  margin-bottom: 8px;
  color: var(--primary);
}

.voice-transcript {
  font-family: 'Inter', sans-serif;
  font-size: 14px;
  color: var(--ink-muted);
  min-height: 24px;
  margin-bottom: 20px;
  font-style: italic;
  line-height: 1.4;
}

.voice-bars {
  display: flex;
  gap: 6px;
  height: 40px;
  align-items: center;
}

.voice-bars .bar {
  width: 4px;
  height: 12px;
  background: var(--accent-blue);
  border-radius: 2px;
  transition: height 0.1s ease;
}

.voice-bars .b1, .voice-bars .b5 { background: var(--grad-violet); }
.voice-bars .b2, .voice-bars .b4 { background: var(--grad-magenta); }
.voice-bars .b3 { background: var(--accent-blue); }

/* Voice trigger inside search bar */
.voice-search-trigger {
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid var(--hairline);
  border-radius: 50%;
  width: 38px;
  height: 38px;
  display: flex;
  align-items: center; 
  justify-content: center;
  cursor: pointer;
  color: var(--ink-muted);
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  margin-left: 8px;
  flex-shrink: 0;
}

.voice-search-trigger:hover {
  background: rgba(106, 76, 245, 0.15);
  border-color: var(--grad-violet);
  color: var(--primary);
  box-shadow: 0 0 12px rgba(106, 76, 245, 0.3);
  transform: scale(1.08);
}

/* Enhanced results layout containing gauges */
.enhanced-result-card {
  transition: transform 0.25s cubic-bezier(0.4, 0, 0.2, 1), box-shadow 0.25s ease;
}

.enhanced-result-card:hover {
  transform: translateY(-2px);
  box-shadow: var(--shadow-premium);
}

.similarity-gauge-wrapper svg {
  transform: rotate(-90deg);
}

.similarity-gauge-wrapper circle {
  stroke-dashoffset: 0;
  stroke-linecap: round;
}

/* Custom styles for Sparkline preview in Advanced Injector */
#vectorProfileBars div {
  border-radius: 1px 1px 0 0;
  transition: height 0.3s ease, background-color 0.3s ease;
}

/* Plot theme pills overrides */
#themePills .pill {
  transition: all 0.25s ease;
}

#themePills .pill:hover {
  transform: translateY(-1px);
}
